function BreathingRings({coherence}:{coherence:number}){const canvasRef=useRef(null);const cohRef=useRef(coherence);useEffect(()=>{cohRef.current=coherence;},[coherence]);useEffect(()=>{const canvas=canvasRef.current;if(!canvas)return;const ctx=canvas.getContext("2d");if(!ctx)return;let frameId;let lastFrame=0;function resize(){canvas.width=window.innerWidth;canvas.height=window.innerHeight;}resize();window.addEventListener("resize",resize);const rings=[{phase:0,speed:0.00012,maxR:1.8,delay:0},{phase:Math.PI*0.5,speed:0.00010,maxR:1.6,delay:0},{phase:Math.PI*1.1,speed:0.00014,maxR:1.4,delay:0},{phase:Math.PI*1.7,speed:0.00011,maxR:1.9,delay:0}];function draw(ts){frameId=requestAnimationFrame(draw);if(ts-lastFrame<40)return;lastFrame=ts;const coh=cohRef.current;ctx.clearRect(0,0,canvas.width,canvas.height);const cx=canvas.width/2,cy=canvas.height*0.44;rings.forEach(ring=>{ring.phase+=ring.speed*(1+coh*0.4);const prog=(Math.sin(ring.phase)+1)/2;const radius=prog*Math.max(canvas.width,canvas.height)*ring.maxR;const alpha=(1-prog)*0.11*(0.5+coh*0.5);if(alpha<0.003)return;ctx.beginPath();ctx.arc(cx,cy,radius,0,Math.PI*2);ctx.strokeStyle="rgba(200,98,26,"+alpha+")";ctx.lineWidth=1.2+coh*0.8;ctx.stroke();});} draw(0);return()=>{cancelAnimationFrame(frameId);window.removeEventListener("resize",resize);};},[]);return(<canvas ref={canvasRef} style={{position:"fixed" as const,inset:0,width:"100%",height:"100%",zIndex:0,pointerEvents:"none" as const,opacity:1}}/>);}
